#!/usr/bin/env python3
from pathlib import Path

ROOT = Path.cwd()
required = ["package.json", "app"]
for rel in required:
    if not (ROOT / rel).exists():
        raise FileNotFoundError(f"No encuentro {rel}. Ejecuta este script desde la raíz del proyecto mundial-porra-2026.")

(ROOT / "app/page.tsx").write_text('import { StandingCard } from "@/components/StandingCard";\nimport { formatDateSection, resultLabel } from "@/lib/format";\nimport { getFootballDataResults } from "@/lib/footballData";\nimport { getMatches, getStandings } from "@/lib/scoring";\n\nexport const revalidate = 600;\n\ntype ResultsPayload = Awaited<ReturnType<typeof getFootballDataResults>>;\n\nfunction getLastFinishedMatch(results: ResultsPayload["results"]) {\n  return getMatches()\n    .filter((match) => results[match.id]?.status === "FINISHED")\n    .sort((a, b) => {\n      const dateA = `${a.date ?? ""}-${String(a.id).padStart(3, "0")}`;\n      const dateB = `${b.date ?? ""}-${String(b.id).padStart(3, "0")}`;\n      return dateB.localeCompare(dateA);\n    })[0];\n}\n\nexport default async function HomePage() {\n  const payload = await getFootballDataResults();\n  const standings = getStandings(payload.results);\n  const played = Object.keys(payload.results).length;\n  const total = getMatches().length;\n  const lastMatch = getLastFinishedMatch(payload.results);\n  const lastResult = lastMatch ? payload.results[lastMatch.id] : undefined;\n\n  return (\n    <section className="screen final-screen">\n      <header className="page-header final-header">\n        <div className="section-label">🏆 Mundial 2026</div>\n        <h1>Clasificación</h1>\n        <p>{played}/{total} partidos puntuados</p>\n      </header>\n\n      {payload.error ? (\n        <div className="system-notice">Actualizando resultados...</div>\n      ) : null}\n\n      {lastMatch && lastResult ? (\n        <section className="last-result-card final-last-result">\n          <div>\n            <span className="section-label">Último resultado</span>\n            <h2>{lastMatch.home} - {lastMatch.away}</h2>\n            <p>{formatDateSection(lastMatch.date)}</p>\n          </div>\n          <strong>{resultLabel(lastResult)}</strong>\n        </section>\n      ) : null}\n\n      <section className="final-ranking-list">\n        {standings.map((row, index) => (\n          <StandingCard key={row.player} row={row} position={index + 1} compact />\n        ))}\n      </section>\n    </section>\n  );\n}\n', encoding="utf-8")

css_path = ROOT / "app/globals.css"
css = css_path.read_text(encoding="utf-8")

markers = [
    "/* V8 final design */",
    "/* Compact home polish */",
    "/* Classification-only home */",
    "/* Sports polish: typography, classification and non-technical status */",
    "/* Rescue clean design after V8 rollback */",
    "/* Stable visual baseline */",
    "/* UI consistency pass */",
    "/* Surgical layout fix: width, tabs and consistent pages */",
    "/* FINAL LAYOUT FIX - compact, stable, no experimental layout */",
]

for marker in markers:
    while marker in css:
        start = css.index(marker)
        next_positions = [css.find(m, start + len(marker)) for m in markers if css.find(m, start + len(marker)) != -1]
        end = min(next_positions) if next_positions else len(css)
        css = css[:start].rstrip() + "\n\n" + css[end:].lstrip()

css = css.rstrip() + "\n\n" + '/* FINAL LAYOUT FIX - compact, stable, no experimental layout */\n:root {\n  --app-bg: #fff4d8;\n  --app-card: rgba(255, 255, 255, 0.88);\n  --app-border: rgba(20, 16, 9, 0.12);\n  --app-text: #17130c;\n  --app-muted: #7c705f;\n  --app-accent: #ffb21a;\n}\n\nhtml,\nbody {\n  background: var(--app-bg) !important;\n  color: var(--app-text) !important;\n  font-family: -apple-system, BlinkMacSystemFont, "SF Pro Text", "Segoe UI", Roboto, Arial, sans-serif !important;\n}\n\n.screen.final-screen,\n.screen {\n  width: 100% !important;\n  max-width: 520px !important;\n  margin: 0 auto !important;\n  padding: 14px 14px 92px !important;\n  box-sizing: border-box !important;\n}\n\n.page-header.final-header,\n.page-header,\n.app-header {\n  margin: 0 !important;\n  padding: 6px 0 14px !important;\n  border: 0 !important;\n  background: transparent !important;\n  box-shadow: none !important;\n}\n\n.section-label {\n  color: #946400 !important;\n  font-size: 12px !important;\n  line-height: 1.2 !important;\n  font-weight: 800 !important;\n  letter-spacing: 0.04em !important;\n  text-transform: uppercase !important;\n}\n\n.page-header h1,\n.app-header h1 {\n  margin: 6px 0 0 !important;\n  color: var(--app-text) !important;\n  font-size: 42px !important;\n  line-height: 0.98 !important;\n  font-weight: 820 !important;\n  letter-spacing: -0.05em !important;\n}\n\n.page-header p,\n.app-header p {\n  margin: 8px 0 0 !important;\n  color: var(--app-muted) !important;\n  font-size: 17px !important;\n  line-height: 1.25 !important;\n  font-weight: 650 !important;\n}\n\n/* Ranking: one compact list, no giant podium cards */\n.final-ranking-list {\n  display: grid !important;\n  gap: 8px !important;\n  margin-top: 10px !important;\n}\n\n.final-ranking-list .standing-row,\n.standing-row.compact,\n.standing-row {\n  display: grid !important;\n  grid-template-columns: 42px minmax(0, 1fr) auto !important;\n  align-items: center !important;\n  gap: 10px !important;\n  min-height: 58px !important;\n  padding: 10px 12px !important;\n  border: 1px solid var(--app-border) !important;\n  border-radius: 18px !important;\n  background: var(--app-card) !important;\n  box-shadow: 0 8px 20px rgba(58, 42, 13, 0.045) !important;\n  text-decoration: none !important;\n}\n\n.final-ranking-list .standing-position,\n.standing-position {\n  min-width: 32px !important;\n  width: 32px !important;\n  color: var(--app-muted) !important;\n  font-size: 16px !important;\n  font-weight: 800 !important;\n  text-align: center !important;\n}\n\n.final-ranking-list .standing-person,\n.standing-person {\n  min-width: 0 !important;\n}\n\n.final-ranking-list .standing-name,\n.standing-name {\n  color: var(--app-text) !important;\n  font-size: 18px !important;\n  line-height: 1.05 !important;\n  font-weight: 800 !important;\n  letter-spacing: -0.02em !important;\n  white-space: nowrap !important;\n  overflow: hidden !important;\n  text-overflow: ellipsis !important;\n}\n\n.final-ranking-list .muted,\n.muted {\n  color: var(--app-muted) !important;\n  font-size: 13px !important;\n  line-height: 1.15 !important;\n  font-weight: 500 !important;\n}\n\n.final-ranking-list .standing-points,\n.standing-points {\n  display: grid !important;\n  justify-items: end !important;\n  min-width: 40px !important;\n}\n\n.final-ranking-list .standing-points strong,\n.standing-points strong {\n  color: var(--app-text) !important;\n  font-size: 30px !important;\n  line-height: 0.9 !important;\n  font-weight: 820 !important;\n  letter-spacing: -0.04em !important;\n}\n\n.final-ranking-list .standing-points span,\n.standing-points span {\n  color: var(--app-muted) !important;\n  font-size: 10px !important;\n  line-height: 1 !important;\n  font-weight: 800 !important;\n  letter-spacing: 0.08em !important;\n}\n\n/* Keep old blocks/cards consistent but not huge */\n.block,\n.quiet-card,\n.match-card,\n.player-row,\n.last-result-card {\n  border: 1px solid var(--app-border) !important;\n  background: var(--app-card) !important;\n  box-shadow: 0 8px 20px rgba(58, 42, 13, 0.045) !important;\n}\n\n.block {\n  margin-top: 12px !important;\n  padding: 12px !important;\n  border-radius: 20px !important;\n}\n\n.block-heading {\n  margin-bottom: 10px !important;\n}\n\n.block-heading h2,\n.date-title h2,\n.quiet-card h2 {\n  color: var(--app-text) !important;\n  font-size: 28px !important;\n  line-height: 1.05 !important;\n  font-weight: 820 !important;\n  letter-spacing: -0.04em !important;\n}\n\n/* Last result */\n.final-last-result,\n.last-result-card {\n  display: flex !important;\n  align-items: center !important;\n  justify-content: space-between !important;\n  gap: 12px !important;\n  margin-top: 4px !important;\n  margin-bottom: 10px !important;\n  padding: 12px 14px !important;\n  border-radius: 18px !important;\n}\n\n.last-result-card h2 {\n  margin: 4px 0 2px !important;\n  color: var(--app-text) !important;\n  font-size: 21px !important;\n  line-height: 1.05 !important;\n  font-weight: 800 !important;\n  letter-spacing: -0.03em !important;\n}\n\n.last-result-card p {\n  margin: 0 !important;\n  color: var(--app-muted) !important;\n  font-size: 13px !important;\n}\n\n.last-result-card strong {\n  flex: 0 0 auto !important;\n  padding: 9px 11px !important;\n  border-radius: 14px !important;\n  background: var(--app-text) !important;\n  color: #fff7df !important;\n  font-size: 20px !important;\n  line-height: 1 !important;\n  font-weight: 820 !important;\n}\n\n/* Calendar and prediction pages */\n.player-list,\n.date-stack {\n  margin-top: 10px !important;\n}\n\n.date-section {\n  margin-top: 18px !important;\n}\n\n.date-section:first-child {\n  margin-top: 0 !important;\n}\n\n.match-card {\n  padding: 14px !important;\n  border-radius: 20px !important;\n}\n\n.match-topline {\n  margin-bottom: 14px !important;\n}\n\n.match-main {\n  margin-bottom: 10px !important;\n}\n\n.team {\n  color: var(--app-text) !important;\n  font-size: 24px !important;\n  line-height: 1.05 !important;\n  font-weight: 800 !important;\n  letter-spacing: -0.03em !important;\n}\n\n.score {\n  min-width: 48px !important;\n  min-height: 42px !important;\n  padding: 8px 10px !important;\n  border-radius: 14px !important;\n}\n\n.match-time {\n  margin-bottom: 12px !important;\n  font-size: 14px !important;\n}\n\n.pick-row {\n  gap: 7px !important;\n}\n\n.pick-button {\n  min-height: 40px !important;\n  padding: 8px 12px !important;\n  border-radius: 16px !important;\n}\n\n.system-notice {\n  margin: 2px 0 8px !important;\n  padding: 10px 12px !important;\n  border: 1px solid rgba(154, 106, 0, 0.18) !important;\n  border-radius: 16px !important;\n  background: #fff0c2 !important;\n  color: #8a5b00 !important;\n  font-size: 14px !important;\n  font-weight: 750 !important;\n}\n\n/* Bottom nav: fixed, visible, four equal tabs */\n.bottom-nav {\n  position: fixed !important;\n  left: 50% !important;\n  right: auto !important;\n  bottom: max(10px, env(safe-area-inset-bottom)) !important;\n  transform: translateX(-50%) !important;\n  width: min(496px, calc(100vw - 20px)) !important;\n  max-width: min(496px, calc(100vw - 20px)) !important;\n  height: 58px !important;\n  display: grid !important;\n  grid-template-columns: repeat(4, minmax(0, 1fr)) !important;\n  gap: 4px !important;\n  padding: 5px !important;\n  border: 1px solid var(--app-border) !important;\n  border-radius: 999px !important;\n  background: rgba(255, 250, 237, 0.96) !important;\n  box-shadow: 0 8px 28px rgba(50, 35, 9, 0.13) !important;\n  backdrop-filter: blur(18px) !important;\n  box-sizing: border-box !important;\n  z-index: 9999 !important;\n  overflow: hidden !important;\n}\n\n.bottom-nav a {\n  min-width: 0 !important;\n  width: 100% !important;\n  height: 48px !important;\n  display: flex !important;\n  align-items: center !important;\n  justify-content: center !important;\n  padding: 0 2px !important;\n  border-radius: 999px !important;\n  color: var(--app-muted) !important;\n  font-size: clamp(11px, 3.05vw, 13px) !important;\n  line-height: 1 !important;\n  font-weight: 800 !important;\n  text-align: center !important;\n  white-space: nowrap !important;\n  letter-spacing: -0.02em !important;\n  text-decoration: none !important;\n  box-sizing: border-box !important;\n  overflow: hidden !important;\n  text-overflow: ellipsis !important;\n}\n\n.bottom-nav a.active {\n  background: var(--app-accent) !important;\n  color: var(--app-text) !important;\n}\n\n/* Remove old accidental elements */\n.live-badge,\n.leader-note,\n.podium {\n  display: none !important;\n}\n\n@media (max-width: 390px) {\n  .screen.final-screen,\n  .screen {\n    padding-left: 12px !important;\n    padding-right: 12px !important;\n  }\n\n  .page-header h1,\n  .app-header h1 {\n    font-size: 38px !important;\n  }\n\n  .page-header p,\n  .app-header p {\n    font-size: 16px !important;\n  }\n\n  .bottom-nav a {\n    font-size: 11px !important;\n    letter-spacing: -0.04em !important;\n  }\n}\n' + "\n"
css_path.write_text(css, encoding="utf-8")

print("Corrección final aplicada:")
print("- Home con lista compacta, sin tarjetas gigantes.")
print("- Barra inferior fija, completa y visible.")
print("- Menos altura vertical en ranking, partidos y tarjetas.")
print("- Sin próximo partido en Clasificación.")
print("- Último resultado solo si existe.")
print("")
print("Ejecuta:")
print("npm run build")
print("git add .")
print("git commit -m 'Final compact layout fix'")
print("git push")
print("npx vercel --prod")
